const columns: KanbanColumn[] = [
  { id: 'todo', title: 'To Do', color: '#6366f1' },
  { id: 'doing', title: 'In Progress', color: '#f59e0b' },
  { id: 'done', title: 'Done', color: '#10b981' },
];

const { items, moveItem, addItem } = useKanban({
  initialItems: tasks.map(t => ({ ...t, columnId: t.status })),
  onItemMoved: (item, from, to) => updateTask(item.id, { status: to }),
});

<KanbanBoard
  columns={columns}
  items={items}
  onMoveItem={moveItem}
  onAddItem={(colId) => openCreateModal(colId)}
/>
